const OverflowEscape = function Render() {
  const [show, setShow] = useState(false);
  const { t } = useTranslation(ALL_NAMESPACES);
  return (
    <Card
      variant="outline"
      padding="lg"
      style={{
        width: "100%",
        maxWidth: "400px",
        height: "250px",
        padding: "32px",
        position: "relative",
        overflow: "hidden",
      }}
    >
      <Card.Body
        style={{
          height: "100%",
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          justifyContent: "center",
        }}
      >
        <div style={{ textAlign: "center", marginBottom: "16px" }}>
          <p
            dangerouslySetInnerHTML={{
              __html: t("story_portal_desc_overflow"),
            }}
          />
          <p>{t("story_portal_desc_escape")}</p>
        </div>

        <Button
          onClick={() => setShow(!show)}
          label={show ? t("story_portal_btn_hide") : t("story_portal_btn_show")}
          priority="primary"
        />

        {show && (
          <Portal>
            <Card
              variant="elevated"
              padding="lg"
              style={{
                position: "fixed",
                bottom: "40px",
                right: "40px",
                width: "280px",
                maxWidth: "calc(100vw - 80px)",
                zIndex: 10000,
                animation: "popUp 0.3s ease-out",
              }}
            >
              <style>{`
                                @keyframes popUp {
                                    from { transform: translateY(20px); opacity: 0; }
                                    to { transform: translateY(0); opacity: 1; }
                                }
                            `}</style>
              <Stack gap="xs">
                <h4 style={{ margin: "0 0 8px 0", color: "var(--wim-primary)" }}>
                  {t("story_portal_power_title")}
                </h4>
                <p
                  style={{ margin: 0, fontSize: "14px", lineHeight: "1.5" }}
                  dangerouslySetInnerHTML={{ __html: t("story_portal_power_desc") }}
                />
                <Box mt="md" textAlign="right">
                  <Button
                    size="small"
                    label={t("story_portal_btn_ok")}
                    onClick={() => setShow(false)}
                  />
                </Box>
              </Stack>
            </Card>
          </Portal>
        )}
      </Card.Body>
    </Card>
  );
};

const CustomContainer = function Render() {
  const [container, setContainer] = useState<HTMLElement | null>(null);
  const { t } = useTranslation(ALL_NAMESPACES);
  return (
    <Container size="md">
      <p>{t("story_portal_container_desc")}</p>

      <SimpleGrid cols={{ base: 1, sm: 2 }} spacing="lg" style={{ marginTop: "24px" }}>
        <Card variant="outline">
          <Card.Header>
            <strong>{t("story_portal_source_title")}</strong>
          </Card.Header>
          <Card.Body>
            <p style={{ fontSize: "12px" }}>
              {t("story_portal_source_desc")}
            </p>
            <Box mt="md" style={{ display: "flex", justifyContent: "center" }}>
              <Portal container={container}>
                <Alert
                  status="success"
                  icon={<Icon name="CheckCircleIcon" />}
                  style={{ width: "fit-content" }}
                >
                  {t("story_portal_sent_success")}
                </Alert>
              </Portal>
            </Box>
          </Card.Body>
        </Card>

        <Box
          ref={setContainer}
          bg="var(--wim-neutral-50, #f8fafc)"
          style={{
            border: "2px dashed var(--wim-primary, #3b82f6)",
            minHeight: "150px",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            borderRadius: "8px",
          }}
        >
          {/* ここに Portal の 中身が表示される */}
          {!container && (
            <Box textAlign="center" color="primary">
              {t("story_portal_loading")}
            </Box>
          )}
        </Box>
      </SimpleGrid>
    </Container>
  );
};

const NotificationCenter = function Render() {
  const [logContainer, setLogContainer] = useState<HTMLElement | null>(
    null,
  );
  const [logs, setLogs] = useState<{ id: string; msg: string; type: string }[]>(
    [],
  );
  const { t } = useTranslation(ALL_NAMESPACES);

  const addLog = (msg: string, type: string = "info") => {
    const id = Math.random().toString(36).slice(2, 9);
    setLogs((prev) => [{ id, msg, type }, ...prev].slice(0, 10));
  };

  const SenderComponent = ({ name: _name, type: _type, color, displayName }: { name?: string; type?: string; color: string; displayName: string }) => {
    const [active, setActive] = useState(false);
    return (
      <Card variant="outline" padding="sm">
        <Stack gap="xs">
          <div
            style={{
              display: "flex",
              justifyContent: "space-between",
              alignItems: "center",
            }}
          >
            <strong>{displayName}</strong>
          </div>
          <Button
            size="small"
            priority={active ? "secondary" : "primary"}
            onClick={() => {
              const newState = !active;
              setActive(newState);
              addLog(
                `${displayName}${newState ? t("story_portal_log_started") : t("story_portal_log_stopped")}`,
                newState ? "success" : "warning",
              );
