    const [items, setItems] = useState(
      Array.from({ length: 20 }, (_, i) => t("story_infscroll_item", { index: i + 1 })),
    );
    const [loading, setLoading] = useState(false);
    const [hasMore, setHasMore] = useState(true);

    const loadMore = () => {
      if (loading || !hasMore) return;
      setLoading(true);
      setTimeout(() => {
        const newItems = Array.from(
          { length: 10 },
          (_, i) => t("story_infscroll_item", { index: items.length + i + 1 }),
        );
        setItems((prev) => [...prev, ...newItems]);
        setLoading(false);
        if (items.length > 50) {
          setHasMore(false);
        }
      }, 1000);
    };

    return (
        <div
            tabIndex={0}
            style={{ height: "400px", overflowY: "auto", padding: "20px" }}>
            <InfiniteScroll loading={loading} hasMore={hasMore} onLoadMore={loadMore}>
